using NutritionTracker.Domain.Common;
namespace NutritionTracker.Domain.Foods;

public sealed class Food : AuditableEntity { public string CanonicalName { get; set; } = string.Empty; public string NormalizedName { get; set; } = string.Empty; public string DisplayName { get; set; } = string.Empty; public string? Description { get; set; } public FoodCategory Category { get; set; } public Cuisine Cuisine { get; set; } public PreparationMethod PreparationMethod { get; set; } public FoodState FoodState { get; set; } public decimal CaloriesPer100Grams { get; set; } public decimal ProteinGramsPer100Grams { get; set; } public decimal CarbohydrateGramsPer100Grams { get; set; } public decimal FatGramsPer100Grams { get; set; } public decimal FibreGramsPer100Grams { get; set; } public decimal? SugarGramsPer100Grams { get; set; } public decimal? SodiumMilligramsPer100Grams { get; set; } public string DataSource { get; set; } = string.Empty; public string? SourceReference { get; set; } public string? SourceVersion { get; set; } public bool IsVerified { get; set; } public bool IsUserCreated { get; set; } public string? OwnerUserId { get; set; } public bool IsActive { get; set; } = true; public ICollection<FoodAlias> Aliases { get; } = new List<FoodAlias>(); public ICollection<FoodServingConversion> ServingConversions { get; } = new List<FoodServingConversion>(); public ICollection<FoodNutrient> Nutrients { get; } = new List<FoodNutrient>(); public ICollection<FoodTagAssignment> TagAssignments { get; } = new List<FoodTagAssignment>(); }
